package config

import (
	"fmt"
	"time"

	couchbasev2 "github.com/couchbase/couchbase-operator/pkg/apis/couchbase/v2"

	appsv1 "k8s.io/api/apps/v1"
	corev1 "k8s.io/api/core/v1"
	rbacv1 "k8s.io/api/rbac/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/util/intstr"

	"github.com/spf13/cobra"
)

const (
	// OperatorResourceName is the name used for all resources generated by the individual functions.
	OperatorResourceName = "couchbase-operator"
)

// generateOperatorOptions defines the options for creating the operator.
type generateOperatorOptions struct {
	// namespace is the namespace into which the resources should be generated.
	namespace string

	// image is the operator image name.
	image string

	// scope is the scope with which to generate the operator.
	scope string

	// imagePullSecret is the name of an image pull secret for authenticating image pulls.
	imagePullSecret string

	// file defines whether or not to output to a file.
	file bool
}

// getGenerateOperatorCommand creates YAML capable of creating the Operator.
func getGenerateOperatorCommand() *cobra.Command {
	o := &generateOperatorOptions{}

	cmd := &cobra.Command{
		Use:   "operator",
		Short: "Generates YAML for the operator",
		Long:  "Generates YAML for the operator",
		RunE: func(cmd *cobra.Command, args []string) error {
			if err := o.validate(); err != nil {
				return err
			}

			return o.generate()
		},
	}

	cmd.Flags().StringVarP(&o.scope, "scope", "s", "namespace", "Whether to scope the Operator to a 'namespace' or to the 'cluster'.")
	cmd.Flags().StringVarP(&o.namespace, "namespace", "n", "default", "Namespace to generate resources in.")
	cmd.Flags().StringVarP(&o.image, "image", "i", operatorImageDefault, "Operator image to use")
	cmd.Flags().StringVarP(&o.imagePullSecret, "image-pull-secret", "p", "", "Image pull secret to allow access to the operator image")
	cmd.Flags().BoolVar(&o.file, "file", false, "Generate files rather than printing to the console")

	return cmd
}

// validate performs any validation that cobra doesn't on options.
func (o *generateOperatorOptions) validate() error {
	if err := validateScope(o.scope); err != nil {
		return err
	}

	return nil
}

// generate dumps all operator resources to standard out.
func (o *generateOperatorOptions) generate() error {
	var imagePullSecrets []string

	if o.imagePullSecret != "" {
		imagePullSecrets = []string{
			o.imagePullSecret,
		}
	}

	if err := DumpYAML(o.file, "operator-service-account", GetOperatorServiceAccount(o.namespace)); err != nil {
		return err
	}

	if err := DumpYAML(o.file, "operator-role", GetOperatorRole(o.namespace, o.scope == scopeCluster)); err != nil {
		return err
	}

	if err := DumpYAML(o.file, "operator-role-binding", GetOperatorRoleBinding(o.namespace, o.scope == scopeCluster)); err != nil {
		return err
	}

	if err := DumpYAML(o.file, "operator-deployment", GetOperatorDeployment(o.namespace, o.image, imagePullSecrets, o.scope == scopeCluster, 10*time.Minute)); err != nil {
		return err
	}

	if err := DumpYAML(o.file, "operator-service", GenerateOperatorService(o.namespace)); err != nil {
		return err
	}

	return nil
}

// GetOperatorRole generates the cluster role to run with.
func GetOperatorRole(namespace string, cluster bool) metav1.Object {
	metadata := metav1.ObjectMeta{
		Name:      OperatorResourceName,
		Namespace: namespace,
	}

	rules := []rbacv1.PolicyRule{
		{
			APIGroups: []string{
				"batch",
			},
			Resources: []string{
				"jobs",
				"cronjobs",
			},
			Verbs: []string{
				"list",
				"watch",
				"create",
				"update",
				"delete",
			},
		},
		{
			APIGroups: []string{
				couchbasev2.GroupName,
			},
			Resources: []string{
				couchbasev2.ClusterCRDResourcePlural,
				// Not supported by GKE 1.13 for some odd reason
				// couchbasev2.ClusterCRDResourcePlural + "/status",
			},
			Verbs: []string{
				"get",    // used by the operator to update status.
				"list",   // used by the operator-sdk to discover couchbase clusters.
				"watch",  // used by the operator-sdk to monitor changes.
				"update", // used by the operator to update status.
			},
		},
		{
			APIGroups: []string{
				couchbasev2.GroupName,
			},
			Resources: []string{
				couchbasev2.BucketCRDResourcePlural,
				couchbasev2.EphemeralBucketCRDResourcePlural,
				couchbasev2.MemcachedBucketCRDResourcePlural,
				couchbasev2.ReplicationCRDResourcePlural,
				couchbasev2.UserCRDResourcePlural,
				couchbasev2.GroupCRDResourcePlural,
				couchbasev2.RoleBindingCRDResourcePlural,
				couchbasev2.BackupCRDResourcePlural,
			},
			Verbs: []string{
				"list",  // used by the operator for caching
				"watch", // used by the operator for caching
			},
		},
		{
			APIGroups: []string{
				couchbasev2.GroupName,
			},
			Resources: []string{
				couchbasev2.BackupRestoreCRDResourcePlural,
			},
			Verbs: []string{
				"list",   // used by the operator for caching
				"watch",  // used by the operator for caching
				"delete", // used by the operator to cleanup restores
			},
		},
		{
			APIGroups: []string{
				couchbasev2.GroupName,
			},
			Resources: []string{
				couchbasev2.AutoscalerCRDResourcePlural,
			},
			Verbs: []string{
				"list",   // used by the operator for caching
				"watch",  // used by the operator for caching
				"create", // used by the operator to create resources
				"delete", // used to cleanup unused resources
			},
		},
		{
			APIGroups: []string{
				couchbasev2.GroupName,
			},
			Resources: []string{
				couchbasev2.AutoscalerCRDResourcePlural + "/status",
			},
			Verbs: []string{
				"update", // used by the operator to update status subresource
			},
		},
		{
			APIGroups: []string{
				"",
			},
			Resources: []string{
				"configmaps",
			},
			Verbs: []string{
				"get",    // used by the controller-runtime for leadership.
				"create", // used by the controller-runtime for leadership.
				"update", // used by the controller-runtime for leadership.
				"delete", // used to migrate persistent state to 2.1
			},
		},
		{
			APIGroups: []string{
				"",
			},
			Resources: []string{
				"pods",
				"pods/status",
				"services",
				"persistentvolumeclaims",
			},
			Verbs: []string{
				"get",    // used by the operator to get specific resources.
				"list",   // used by the operator for caching
				"watch",  // used by the operator for caching
				"create", // used by the operator to create resources.
				"update", // used by the operator to modify resources.
				"delete", // used by the operator to delete resources.
				"patch",  // used by the operator to modify resources.
			},
		},
		{
			APIGroups: []string{
				"",
			},
			Resources: []string{
				"events",
			},
			Verbs: []string{
				"list",   // used by the operator for supportability.
				"create", // used by the operator to create events.
				"update", // used by the operator to update events.
			},
		},
		{
			APIGroups: []string{
				"",
			},
			Resources: []string{
				"secrets",
			},
			Verbs: []string{
				"get",    // used by the operator to get cluster and TLS secrets.
				"create", // used by the operator for persistent state
				"update", // used by the operator for persistent state
				"list",   // used by the operator for caching
				"watch",  // used by the operator for caching
			},
		},
		// Require read/write of pod disruption budgets.
		{
			APIGroups: []string{
				"policy",
			},
			Resources: []string{
				"poddisruptionbudgets",
			},
			Verbs: []string{
				"get",    // used by the operator to get pod disruption budgets.
				"create", // used by the operator to create pod disruption budgets.
				"delete", // used by the operator to delete pod disruption budgets.
				"list",   // used by the operator for caching
				"watch",  // used by the operator for caching
			},
		},
	}

	if cluster {
		return &rbacv1.ClusterRole{
			TypeMeta: metav1.TypeMeta{
				APIVersion: "rbac.authorization.k8s.io/v1",
				Kind:       "ClusterRole",
			},
			ObjectMeta: metadata,
			Rules:      rules,
		}
	}

	return &rbacv1.Role{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "rbac.authorization.k8s.io/v1",
			Kind:       "Role",
		},
		ObjectMeta: metadata,
		Rules:      rules,
	}
}

// GetOperatorServiceAccount generates the service account to run as.
func GetOperatorServiceAccount(namespace string) *corev1.ServiceAccount {
	return &corev1.ServiceAccount{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "v1",
			Kind:       "ServiceAccount",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      OperatorResourceName,
			Namespace: namespace,
		},
	}
}

// GetOperatorRoleBinding generates the cluster role binding linking the role to the service account.
func GetOperatorRoleBinding(namespace string, cluster bool) metav1.Object {
	metadata := metav1.ObjectMeta{
		Name:      OperatorResourceName,
		Namespace: namespace,
	}

	subjects := []rbacv1.Subject{
		{
			Kind:      "ServiceAccount",
			Name:      OperatorResourceName,
			Namespace: namespace,
		},
	}

	if cluster {
		return &rbacv1.ClusterRoleBinding{
			TypeMeta: metav1.TypeMeta{
				APIVersion: "rbac.authorization.k8s.io/v1",
				Kind:       "ClusterRoleBinding",
			},
			ObjectMeta: metadata,
			Subjects:   subjects,
			RoleRef: rbacv1.RoleRef{
				APIGroup: "rbac.authorization.k8s.io",
				Kind:     "ClusterRole",
				Name:     OperatorResourceName,
			},
		}
	}

	return &rbacv1.RoleBinding{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "rbac.authorization.k8s.io/v1",
			Kind:       "RoleBinding",
		},
		ObjectMeta: metadata,
		Subjects:   subjects,
		RoleRef: rbacv1.RoleRef{
			APIGroup: "rbac.authorization.k8s.io",
			Kind:     "Role",
			Name:     OperatorResourceName,
		},
	}
}

// GetOperatorDeployment returns the canonical way to run the operator.
func GetOperatorDeployment(namespace, image string, imagePullSecrets []string, cluster bool, podCreateTimeout fmt.Stringer, extraArgs ...string) *appsv1.Deployment {
	replicas := int32(1)

	// IF we are running namespace scoped, then use the namespace metadata
	// to set the environment variable and imit the Operator.  If not then
	// set it to "" and let it have free reign over the whole cluster.
	namespaceEnv := corev1.EnvVar{
		Name: "WATCH_NAMESPACE",
	}

	if !cluster {
		namespaceEnv.ValueFrom = &corev1.EnvVarSource{
			FieldRef: &corev1.ObjectFieldSelector{
				FieldPath: "metadata.namespace",
			},
		}
	}

	deployment := &appsv1.Deployment{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "apps/v1",
			Kind:       "Deployment",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      OperatorResourceName,
			Namespace: namespace,
		},
		Spec: appsv1.DeploymentSpec{
			Replicas: &replicas,
			Selector: &metav1.LabelSelector{
				MatchLabels: map[string]string{
					"app": OperatorResourceName,
				},
			},
			Template: corev1.PodTemplateSpec{
				ObjectMeta: metav1.ObjectMeta{
					Labels: map[string]string{
						"app": OperatorResourceName,
					},
				},
				Spec: corev1.PodSpec{
					ServiceAccountName: OperatorResourceName,
					Containers: []corev1.Container{
						{
							Name:  OperatorResourceName,
							Image: image,
							Command: []string{
								OperatorResourceName,
							},
							Args: append([]string{
								"--pod-create-timeout=" + podCreateTimeout.String(),
							}, extraArgs...),
							Env: []corev1.EnvVar{
								namespaceEnv,
								{
									Name: "POD_NAME",
									ValueFrom: &corev1.EnvVarSource{
										FieldRef: &corev1.ObjectFieldSelector{
											FieldPath: "metadata.name",
										},
									},
								},
							},
							Ports: []corev1.ContainerPort{
								{
									Name:          "http",
									ContainerPort: 8080,
								},
								{
									Name:          "prometheus",
									ContainerPort: 8383,
								},
							},
							ReadinessProbe: &corev1.Probe{
								Handler: corev1.Handler{
									HTTPGet: &corev1.HTTPGetAction{
										Path:   "/readyz",
										Port:   intstr.FromString("http"),
										Scheme: corev1.URISchemeHTTP,
									},
								},
							},
						},
					},
				},
			},
		},
	}

	for _, secret := range imagePullSecrets {
		reference := corev1.LocalObjectReference{
			Name: secret,
		}

		deployment.Spec.Template.Spec.ImagePullSecrets = append(deployment.Spec.Template.Spec.ImagePullSecrets, reference)
	}

	return deployment
}

// Required by istio.
func GenerateOperatorService(namespace string) *corev1.Service {
	return &corev1.Service{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "v1",
			Kind:       "Service",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      OperatorResourceName,
			Namespace: namespace,
		},
		Spec: corev1.ServiceSpec{
			Selector: map[string]string{
				"app": OperatorResourceName,
			},
			Ports: []corev1.ServicePort{
				{
					Name:       "http-pprof",
					Protocol:   corev1.ProtocolTCP,
					Port:       8080,
					TargetPort: intstr.FromInt(8080),
				},
				{
					Name:       "http-prometheus",
					Protocol:   corev1.ProtocolTCP,
					Port:       8383,
					TargetPort: intstr.FromInt(8383),
				},
			},
		},
	}
}
